var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在你腦海中的那個機械……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"不，是那個孩子，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 부르자, 약속한 장소에서 기다리고 있겠다는 대답이 돌아왔다.","JPN":"意を決して彼女を呼び出すと、約束の場所で待っているとの返事が返ってきた。","ENG":"Having decided that, you called her. She answered she'd be waiting for you at the place you promised to meet.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"야호! 나도 동화 속 공주들처럼 결혼식을 한 번쯤 해보고 싶었어!","JPN":"やったー！私も昔話のお姫様のように、一度ぐらい結婚式をやってみたかったの！","ENG":"Woohoo! I've always wanted to get married like the princesses in the fairy tales!","TWN":"耶～！我也想像童話中的公主一樣，舉辦一場盛大的婚禮！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"부부가 된다는 건 가족 단계 중에서도 최고 레벨이 되는 거지?","JPN":"夫婦になるっていうのは、家族の中でも最高レベルになるってことでしょ？","ENG":"Getting married is like the closest you can be as family, right?","TWN":"結為夫妻就是成為家庭中的最高級別吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"응? 아빠랑은 결혼하면 안돼?","JPN":"うん？パパとは結婚しちゃだめ？","ENG":"What? Daughters aren't supposed to marry their daddies?","TWN":"嗯？不能跟爸爸結婚嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"그치만 서로 좋아하면 결혼하는 거라고 했단 말이야!","JPN":"でも、両思いになると結婚するんだって言われたもん！","ENG":"But I heard people get married if they like each other!","TWN":"可是不是說互相喜歡就可以結婚嗎！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"으으, 아빤 맨날 안된다고만 해!","JPN":"ううっ、パパはいつもダメばかり！","ENG":"Oh, come on, Daddy! You never let me do anything!","TWN":"嗚嗚，爸爸每天就只會說不行！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"흥!","JPN":"ふんっ！","ENG":"Hmpf!","TWN":"哼！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"그치만 미래를 위해 예행연습 정도는 아빠랑 같이 해봐도 되는 거잖아?","JPN":"でも、未来のために予行練習ぐらいはパパと一緒にしてもいいよね？","ENG":"But at least I can practice with you for my future wedding, right?","TWN":"可是為了將來，跟爸爸一起彩排一下總是可以的吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"내 말 맞지? 응?","JPN":"そうでしょ？ね？","ENG":"Isn't that right? Hmm?","TWN":"我說得對吧？嗯？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"좋았어! 빨리 해보자! 히힛!","JPN":"やった！じゃあさっそくやって見ようよ！ヘへっ！","ENG":"Great! Let's give it a try! Hee hee!","TWN":"太棒了！快點來彩排吧！嘻嘻！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"아하하! 신부! 정시에 도착했도다~!","JPN":"アハハ！新婦！入～場～！","ENG":"Ah hah hah! Here comes the bride! Right on time!","TWN":"啊哈哈！新娘！準時到達啦～！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"시종들이여! 북을 치고 나팔을 불어라~","JPN":"侍従たちよ！太鼓を叩き、ラッパを吹きたまえ～。","ENG":"My servants! Beat your drums and toot your horns!","TWN":"侍從們！打鼓吹喇叭吧～"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"응? 결혼식 이렇게 시작하는 거 아냐?","JPN":"あれ？結婚式ってこんな風に始まるんじゃなかったっけ？","ENG":"Huh? Isn't this how weddings are supposed to start?","TWN":"咦？婚禮不是這樣開始的嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"잠깐만~ 그럼 다른 버전을 찾아볼게!","JPN":"ちょって待ってて～じゃあ、他のバージョンを探してみる！","ENG":"Give me a minute... Let me find a different version!","TWN":"等等～那我找找其他版本！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"아빠는 고개를 들라!","JPN":"パパは頭を上げなさい！","ENG":"You shall raise your head, Daddy!","TWN":"爸爸抬起頭來！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"네 약혼자가 식경이 넘도록 돌아오지 않았으니, 넌 약조한 대로 이 몸과 혼사를 치러야 할 것이야!","JPN":"あなたの婚約者はしばらく経っても帰らずにいる。\\n然れば、あなたは約束どおり私と婚姻すべし！","ENG":"For thy betrothed has yet to arrive, ye shall be wedded to me as promised!","TWN":"你的未婚妻這麼久都還沒回來，所以你就按照約定跟我結婚吧！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"......왜 그렇게 웃어?","JPN":"……なんでそんなに笑ってるの？","ENG":"Why are you laughing?","TWN":"……爸爸你在笑什麼？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"으음, 표정을 보니 이 버전도 제대로 된 결혼식이 아닌 모양이네.","JPN":"う～ん、その表情からすると、このバージョンもまともな結婚式じゃないみたいだね。","ENG":"Hmm... Your face tells me this isn't the right version either.","TWN":"唔嗯，從你的表情來看，這個版本好像也不是正常的婚禮。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"그렇다면 다른 버전을......","JPN":"それなら違うバージョンを……","ENG":"Let me find another version then...","TWN":"那我再找找其他版本……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"앗! 아냐! 더 이상 다른 데이터는 참조하지 않겠어!","JPN":"あっ、違うの！もう他のデータは参考にしないから！","ENG":"Ugh! Forget it! I'm not going to refer to any other data now!","TWN":"啊！算了！我不要再參考其他資料了！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"우린 우리만의 새로운 결혼식 룰을 만드는 거야! 어때?","JPN":"私たちは、私たちならではの新しい結婚式のルールを作ろうよ！どう？","ENG":"We can make our own rules for our wedding! How about that?","TWN":"我們就制定屬於我們自己的新婚典禮規則！怎麼樣？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"아빠가 앉아서 기다리고 있으면, 내가 아빠가 싫어하는 악당들을 모~두 해치우고 돌아온 다음 꽃다발을 내밀면서 서약을 하는 거야!","JPN":"パパが座って待っていると、パパが嫌いな悪い奴らをぜん～ぶ倒して戻ってきた私が、ブーケを捧げながら誓うの！","ENG":"If you just sit tight, I'll go get rid of all the bad guys you hate! Then I'll bring you a bouquet of flowers and we can join in matrimony!","TWN":"爸爸就坐著等我，等我把爸爸討厭的壞蛋全～都解決掉後，獻上花束並許下諾言！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"그럼 아빠도 기뻐하겠지?","JPN":"そうするとパパも喜ぶでしょ？","ENG":"You'll be happy with that too, right?","TWN":"這樣的話爸爸也會很高興吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"응? 안 그래도 돼? 그런 마음만으로도 충분하다니?","JPN":"うん？やらなくてもいい？気持ちだけで充分って？","ENG":"Huh? I don't have to do that? What do you mean it's the thought that counts?","TWN":"嗯？可以不用這樣？只要有那份心意就夠了？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"하지만 소중한 사람을 위해 목숨을 바쳐 싸우는 것만큼 진심을 드러내기 좋은 방법도 없지 않아?","JPN":"でも、大切な人のために命を捧げて戦うことほど、本気を表すいい方法はないでしょ？","ENG":"What's a better way to show someone you love them than putting your life on the line fighting for them?","TWN":"可是再也沒有比為了重要的人獻上生命去戰鬥，更能表明真心的好辦法了不是嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SIGMA_RAS_WEDDING_NULL","text":{"KOREA":"아앗! 영화 일주일 금지라니! 너무해! 갑자기 그러는 법이 어디 있어!","JPN":"あぁっ！一週間映画禁止って！ひどい！いきなりずるいよ！","ENG":"Wah! No movies for a week? Come on! You can't do this to me!","TWN":"什麼！禁止看電影一週？！爸爸你太過分了！哪有這樣的！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_WEDDING_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};